import http from "src/utils/http";

const storeApi = {
  registerStore: () => http.post("/store/register"),
  getProducts: () => http.get("/store/products"),
  createProduct: (body: any) => http.post("/store/products", body),
  updateProduct: (id: string, body: any) => http.put(`/store/products/${id}`, body),
  deleteProduct: (id: string) => http.delete(`/store/products/${id}`),
  getOrders: () => http.get("/store/orders"),
  getDashboard: () => http.get("/store/dashboard"),
};

export default storeApi;

import http from "src/utils/http";

const voucherApi = {
  applyVoucher: (body: { code: string; order_value: number }) => http.post("/vouchers/apply", body),
  createVoucher: (body: any) => http.post("/vouchers", body),
  getVouchers: () => http.get("/vouchers"),
};

export default voucherApi;

import {
  arrow,
  FloatingPortal,
  offset,
  Placement,
  shift,
  useClick,
  useFloating,
  useInteractions,
} from "@floating-ui/react";
import { AnimatePresence, motion } from "framer-motion";
import React, { useRef, useState } from "react";
type PopoverProps = {
  children?: React.ReactNode;
  renderPopover?: React.ReactNode;
  className?: string;
  as?: React.ElementType;
  initialOpen?: boolean;
  placement?: Placement;
};
const Popover = ({
  children,
  renderPopover,
  className,
  initialOpen = false,
  placement = "bottom-end",
  as: Element = "div",
}: PopoverProps) => {
  const arrowRef = useRef<HTMLElement>(null);
  const [isOpen, setIsOpen] = useState<boolean>(initialOpen);
  const { x, y, strategy, refs, context, middlewareData } = useFloating({
    middleware: [offset(10), shift(), arrow({ element: arrowRef })],
    placement: placement,
  });
  const click = useClick(context);
  const { getReferenceProps, getFloatingProps } = useInteractions([click]);

  const showPopover = () => {
    setIsOpen(true);
  };
  const hidePopover = () => {
    setIsOpen(false);
  };
  const togglePopOver = (e: React.TouchEvent<any>) => {
    setIsOpen((prev) => !prev);
  };
  return (
    <Element
      className={className}
      onMouseEnter={showPopover}
      onMouseLeave={hidePopover}
      onTouchEnd={togglePopOver}
      ref={refs.setReference}
      {...getReferenceProps()}
    >
      {children}
      <FloatingPortal>
        <AnimatePresence>
          {isOpen && (
            <motion.div
              ref={refs.setFloating}
              style={{
                position: strategy,
                top: y ?? 0,
                left: x ?? 0,
                width: "max-content",
                transformOrigin: `${middlewareData.arrow?.x}px top`,
                zIndex: 1,
              }}
              initial={{ opacity: 0, transform: "scale(0)" }}
              animate={{ opacity: 1, transform: "scale(1)" }}
              exit={{ opacity: 0, transform: "scale(0)" }}
              transition={{ duration: 0.2 }}
              {...getFloatingProps()}
            >
              <div className="absolute top-0 left-0 h-5 w-full -translate-y-full"></div>
              <span
                className="absolute -translate-y-[98%] border-[11px] border-x-transparent border-t-transparent border-b-white"
                ref={arrowRef}
                style={{
                  left: middlewareData.arrow?.x,
                  top: middlewareData.arrow?.y,
                }}
              ></span>
              {renderPopover}
            </motion.div>
          )}
        </AnimatePresence>
      </FloatingPortal>
    </Element>
  );
};

export default Popover;

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import React from "react";
import { toast } from "react-toastify";
import adminApi from "src/apis/admin.api";
import { formatCurrency } from "src/utils/formatNumber";

export default function Products() {
  const queryClient = useQueryClient();
  const { data } = useQuery({
    queryKey: ["adminProducts"],
    queryFn: adminApi.getProducts,
  });

  const products = data?.data.data || [];

  const deleteMutation = useMutation({
    mutationFn: adminApi.deleteProduct,
    onSuccess: () => {
      toast.success("Gỡ sản phẩm thành công");
      queryClient.invalidateQueries({ queryKey: ["adminProducts"] });
    },
  });

  const handleDelete = (id: string) => {
    if (window.confirm("Bạn có chắc muốn gỡ sản phẩm này khỏi hệ thống?")) {
      deleteMutation.mutate(id);
    }
  };

  return (
    <div className="min-h-[600px] rounded-sm bg-white p-6 shadow-sm">
      <h1 className="mb-6 text-2xl font-medium">Quản lý Sản phẩm (Kiểm duyệt)</h1>

      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead className="bg-gray-50 uppercase text-gray-700">
            <tr>
              <th className="px-4 py-3">Sản phẩm</th>
              <th className="px-4 py-3">Cửa hàng</th>
              <th className="px-4 py-3">Giá</th>
              <th className="px-4 py-3">Đã bán</th>
              <th className="px-4 py-3 text-right">Thao tác</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product: any) => (
              <tr
                key={product._id}
                className="border-b border-gray-100 hover:bg-gray-50"
              >
                <td className="flex items-center gap-3 px-4 py-3">
                  <img
                    src={product.image}
                    alt={product.name}
                    className="h-12 w-12 border object-cover"
                  />
                  <div className="max-w-[200px] line-clamp-2">{product.name}</div>
                </td>
                <td className="px-4 py-3 font-medium text-purple-600">{product.seller?.email || "Shopee"}</td>
                <td className="px-4 py-3 text-primary">₫{formatCurrency(product.price)}</td>
                <td className="px-4 py-3">{product.sold}</td>
                <td className="px-4 py-3 text-right">
                  <button
                    onClick={() => handleDelete(product._id)}
                    className="font-medium text-red-500 hover:underline"
                  >
                    Gỡ bỏ
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import React from "react";
import { toast } from "react-toastify";
import adminApi from "src/apis/admin.api";

export default function Users() {
  const queryClient = useQueryClient();
  const { data } = useQuery({
    queryKey: ["adminUsers"],
    queryFn: adminApi.getUsers,
  });

  const users = data?.data.data || [];

  const toggleLockMutation = useMutation({
    mutationFn: adminApi.toggleLockUser,
    onSuccess: (res) => {
      toast.success(res.data.message);
      queryClient.invalidateQueries({ queryKey: ["adminUsers"] });
    },
  });

  const handleToggleLock = (id: string, isLocked: boolean) => {
    if (window.confirm(`Bạn có chắc muốn ${isLocked ? "mở khóa" : "khóa"} người dùng này?`)) {
      toggleLockMutation.mutate(id);
    }
  };

  return (
    <div className="min-h-[600px] rounded-sm bg-white p-6 shadow-sm">
      <h1 className="mb-6 text-2xl font-medium">Quản lý Người dùng & Cửa hàng</h1>

      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead className="bg-gray-50 uppercase text-gray-700">
            <tr>
              <th className="px-4 py-3">Email</th>
              <th className="px-4 py-3">Tên</th>
              <th className="px-4 py-3">Vai trò</th>
              <th className="px-4 py-3">Trạng thái</th>
              <th className="px-4 py-3 text-right">Thao tác</th>
            </tr>
          </thead>
          <tbody>
            {users.map((user: any) => (
              <tr
                key={user._id}
                className="border-b border-gray-100 hover:bg-gray-50"
              >
                <td className="px-4 py-3 font-medium">{user.email}</td>
                <td className="px-4 py-3">{user.name || "N/A"}</td>
                <td className="px-4 py-3">
                  {user.roles.includes("Store") ? (
                    <span className="rounded-sm bg-purple-100 px-2 py-1 text-xs text-purple-700">Cửa hàng</span>
                  ) : (
                    <span className="rounded-sm bg-blue-100 px-2 py-1 text-xs text-blue-700">Khách hàng</span>
                  )}
                </td>
                <td className="px-4 py-3">
                  {user.isLocked ? (
                    <span className="font-medium text-red-500">Bị khóa</span>
                  ) : (
                    <span className="font-medium text-green-500">Hoạt động</span>
                  )}
                </td>
                <td className="px-4 py-3 text-right">
                  <button
                    onClick={() => handleToggleLock(user._id, user.isLocked)}
                    className={`${user.isLocked ? "text-green-500" : "text-red-500"} font-medium hover:underline`}
                  >
                    {user.isLocked ? "Mở khóa" : "Khóa"}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { useMutation } from "@tanstack/react-query";
import React, { useContext, useMemo, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import Button from "src/components/Button";
import { path } from "src/constants/path.enum";
import { AuthContext } from "src/contexts/auth.context";
import { formatCurrency } from "src/utils/formatNumber";
import http from "src/utils/http";
import voucherApi from "src/apis/voucher.api";

export default function Checkout() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const { userProfile } = useContext(AuthContext);

  const purchases = state?.purchases || [];

  const [shippingAddress, setShippingAddress] = useState(userProfile?.address || "");
  const [shippingMethod, setShippingMethod] = useState("nhanh");
  const [paymentMethod, setPaymentMethod] = useState("cod");

  const [voucherCode, setVoucherCode] = useState("");
  const [discountAmount, setDiscountAmount] = useState(0);
  const [appliedVoucherId, setAppliedVoucherId] = useState<string | null>(null);

  const itemsTotal = useMemo(
    () => purchases.reduce((total: number, p: any) => total + p.product.price * p.buy_count, 0),
    [purchases],
  );

  const shippingFee = shippingMethod === "nhanh" ? 30000 : shippingMethod === "hoatoc" ? 50000 : 15000;
  const totalAmount = Math.max(0, itemsTotal + shippingFee - discountAmount);

  const applyVoucherMutation = useMutation({
    mutationFn: (body: { code: string; order_value: number }) => voucherApi.applyVoucher(body),
    onSuccess: (res) => {
      toast.success(res.data.message);
      setDiscountAmount(res.data.data.discount_amount);
      setAppliedVoucherId(res.data.data.voucher_id);
    },
    onError: (err: any) => {
      toast.error(err.response?.data?.message || "Mã giảm giá không hợp lệ");
      setDiscountAmount(0);
      setAppliedVoucherId(null);
    },
  });

  const handleApplyVoucher = () => {
    if (!voucherCode.trim()) {
      toast.error("Vui lòng nhập mã giảm giá");
      return;
    }
    applyVoucherMutation.mutate({ code: voucherCode, order_value: itemsTotal });
  };

  const checkoutMutation = useMutation({
    mutationFn: (body: any) => http.post("/orders/checkout", body),
    onSuccess: () => {
      toast.success("Đặt hàng thành công");
      navigate(path.orderHistory);
    },
    onError: () => {
      toast.error("Có lỗi xảy ra khi đặt hàng");
    },
  });

  const handleCheckout = () => {
    if (!shippingAddress.trim()) {
      toast.error("Vui lòng nhập địa chỉ giao hàng");
      return;
    }

    if (purchases.length === 0) {
      toast.error("Giỏ hàng trống");
      return;
    }

    const items = purchases.map((p: any) => ({
      product_id: p.product._id,
      buy_count: p.buy_count,
    }));

    checkoutMutation.mutate({
      items,
      shippingAddress,
      shippingMethod,
      shippingFee,
      paymentMethod,
    });
  };

  if (purchases.length === 0) {
    return (
      <div className="container py-10 text-center">
        <h2>Giỏ hàng của bạn đang trống</h2>
        <Button
          onClick={() => navigate(path.home)}
          className="mt-4 bg-primary px-4 py-2 text-white"
        >
          Tiếp tục mua sắm
        </Button>
      </div>
    );
  }

  return (
    <div className="bg-neutral-100 py-10">
      <div className="container">
        <h1 className="mb-6 text-2xl font-medium uppercase">Thanh Toán</h1>

        <div className="grid grid-cols-1 gap-6 md:grid-cols-3">
          <div className="space-y-6 md:col-span-2">
            <div className="rounded-sm border-t-4 border-primary bg-white p-6 shadow-sm">
              <h2 className="mb-4 flex items-center text-lg font-medium text-primary">
                <svg
                  viewBox="0 0 24 24"
                  className="mr-2 h-5 w-5 fill-current"
                >
                  <path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z" />
                </svg>
                Địa chỉ nhận hàng
              </h2>
              <textarea
                className="w-full rounded-sm border border-gray-300 p-3 outline-none focus:border-primary"
                rows={3}
                placeholder="Nhập địa chỉ giao hàng chi tiết..."
                value={shippingAddress}
                onChange={(e) => setShippingAddress(e.target.value)}
              />
            </div>

            <div className="rounded-sm bg-white p-6 shadow-sm">
              <h2 className="mb-4 text-lg font-medium">Sản phẩm</h2>
              {purchases.map((purchase: any) => (
                <div
                  key={purchase._id}
                  className="flex gap-4 border-b border-gray-100 py-4 last:border-0"
                >
                  <img
                    src={purchase.product.image}
                    alt={purchase.product.name}
                    className="h-16 w-16 object-cover"
                  />
                  <div className="flex-1">
                    <div className="text-sm line-clamp-2">{purchase.product.name}</div>
                    <div className="mt-2 text-sm text-gray-500">Số lượng: {purchase.buy_count}</div>
                  </div>
                  <div className="text-sm font-medium">
                    ₫{formatCurrency(purchase.product.price * purchase.buy_count)}
                  </div>
                </div>
              ))}
            </div>

            <div className="rounded-sm bg-white p-6 shadow-sm">
              <h2 className="mb-4 text-lg font-medium">Phương thức vận chuyển</h2>
              <div className="space-y-3">
                <label className="flex cursor-pointer items-center">
                  <input
                    type="radio"
                    name="shipping"
                    value="nhanh"
                    checked={shippingMethod === "nhanh"}
                    onChange={(e) => setShippingMethod(e.target.value)}
                    className="h-4 w-4 text-primary"
                  />
                  <span className="ml-3">Nhanh (₫30.000)</span>
                </label>
                <label className="flex cursor-pointer items-center">
                  <input
                    type="radio"
                    name="shipping"
                    value="hoatoc"
                    checked={shippingMethod === "hoatoc"}
                    onChange={(e) => setShippingMethod(e.target.value)}
                    className="h-4 w-4 text-primary"
                  />
                  <span className="ml-3">Hỏa tốc (₫50.000)</span>
                </label>
                <label className="flex cursor-pointer items-center">
                  <input
                    type="radio"
                    name="shipping"
                    value="tietkiem"
                    checked={shippingMethod === "tietkiem"}
                    onChange={(e) => setShippingMethod(e.target.value)}
                    className="h-4 w-4 text-primary"
                  />
                  <span className="ml-3">Tiết kiệm (₫15.000)</span>
                </label>
              </div>
            </div>

            <div className="rounded-sm bg-white p-6 shadow-sm">
              <h2 className="mb-4 text-lg font-medium">Phương thức thanh toán</h2>
              <div className="space-y-3">
                <label className="flex cursor-pointer items-center">
                  <input
                    type="radio"
                    name="payment"
                    value="cod"
                    checked={paymentMethod === "cod"}
                    onChange={(e) => setPaymentMethod(e.target.value)}
                    className="h-4 w-4 text-primary"
                  />
                  <span className="ml-3">Thanh toán khi nhận hàng (COD)</span>
                </label>
                <label className="flex cursor-pointer items-center">
                  <input
                    type="radio"
                    name="payment"
                    value="bank"
                    checked={paymentMethod === "bank"}
                    onChange={(e) => setPaymentMethod(e.target.value)}
                    className="h-4 w-4 text-primary"
                  />
                  <span className="ml-3">Chuyển khoản ngân hàng</span>
                </label>
              </div>
            </div>
          </div>

          <div className="md:col-span-1">
            <div className="sticky top-6 rounded-sm bg-white p-6 shadow-sm">
              <h2 className="mb-4 text-lg font-medium">Đơn hàng</h2>

              <div className="mb-6">
                <div className="flex gap-2">
                  <input
                    type="text"
                    placeholder="Nhập mã giảm giá"
                    value={voucherCode}
                    onChange={(e) => setVoucherCode(e.target.value)}
                    className="flex-1 rounded-sm border border-gray-300 p-2 uppercase outline-none focus:border-primary"
                  />
                  <Button
                    onClick={handleApplyVoucher}
                    disabled={applyVoucherMutation.isLoading}
                    className="rounded-sm bg-primary px-4 text-white"
                  >
                    Áp dụng
                  </Button>
                </div>
                {appliedVoucherId && (
                  <div className="mt-2 text-sm font-medium text-green-600">Đã áp dụng mã giảm giá!</div>
                )}
              </div>

              <div className="flex justify-between py-2 text-gray-600">
                <span>Tổng tiền hàng</span>
                <span>₫{formatCurrency(itemsTotal)}</span>
              </div>
              <div className="flex justify-between py-2 text-gray-600">
                <span>Phí vận chuyển</span>
                <span>₫{formatCurrency(shippingFee)}</span>
              </div>
              {discountAmount > 0 && (
                <div className="flex justify-between py-2 text-primary">
                  <span>Giảm giá (Voucher)</span>
                  <span>- ₫{formatCurrency(discountAmount)}</span>
                </div>
              )}
              <div className="mt-2 flex justify-between border-t border-gray-200 py-4 font-medium">
                <span>Tổng thanh toán</span>
                <span className="text-2xl text-primary">₫{formatCurrency(totalAmount)}</span>
              </div>
              <Button
                onClick={handleCheckout}
                isLoading={checkoutMutation.isLoading}
                disabled={checkoutMutation.isLoading}
                className="mt-4 w-full bg-primary py-3 uppercase text-white"
              >
                Đặt hàng
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import DOMPurify from "dompurify";
import React, { useState, useContext } from "react";
import { convert } from "html-to-text";
import { Helmet } from "react-helmet-async";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import productApi from "src/apis/product.api";
import purchaseAPI from "src/apis/purchase.api";
import wishlistApi from "src/apis/wishlist.api";
import ProductRating from "src/components/ProductRating";
import QuantityController from "src/components/QuantityController";
import { AuthContext } from "src/contexts/auth.context";
import { path } from "src/constants/path.enum";
import { purchasesStatus } from "src/constants/purchaseStatus.enum";
import { calculateSalePercent, formatCurrency, formatNumberToSocialStyle } from "src/utils/formatNumber";
import { getIdFromSlug } from "src/utils/slugify";
import { FreeMode, Navigation, Thumbs } from "swiper";
import { Swiper, SwiperSlide } from "swiper/react";
// eslint-disable-next-line import/no-unresolved
import { Swiper as SwiperType } from "swiper/types";
import Product from "../ProductList/components/Product";
import Recommendations from "src/components/Recommendations";
import ProductReviews from "./components/ProductReviews";
import { isAxiosError } from "axios";

const ProductDetails = () => {
  const [thumbSwiper, setThumbSwiper] = useState<SwiperType | null>(null);
  const [currentImageState, setCurrentImageState] = useState<HTMLImageElement | null>(null);
  const [currentQuantity, setCurrentQuantity] = useState<number>(1);
  const navigate = useNavigate();
  const { slug } = useParams();
  const id = getIdFromSlug(slug as string);
  const queryClient = useQueryClient();
  const { isAuthenticated } = useContext(AuthContext);
  const { data: productDetailData } = useQuery({
    queryKey: ["product", id],
    queryFn: () => productApi.getProductById(id as string),
    staleTime: 3 * 60 * 1000,
  });
  const product = productDetailData?.data.data;
  const { data: relevantProductListData } = useQuery({
    queryKey: ["relevantProducts", product?.category._id],
    queryFn: () =>
      productApi.getProducts({ category: product?.category._id, sort_by: "sold", order: "desc", limit: "12" }),
    staleTime: 3 * 60 * 1000,
    enabled: Boolean(product),
  });

  React.useEffect(() => {
    if (product) {
      const recentlyViewedStr = localStorage.getItem("recentlyViewed") || "[]";
      let recentlyViewed = JSON.parse(recentlyViewedStr) as string[];
      // Remove if exists and push to top
      recentlyViewed = recentlyViewed.filter((item) => item !== product._id);
      recentlyViewed.unshift(product._id);
      // Keep only last 10
      if (recentlyViewed.length > 10) recentlyViewed = recentlyViewed.slice(0, 10);
      localStorage.setItem("recentlyViewed", JSON.stringify(recentlyViewed));
    }
  }, [product]);

  const addToCartMutation = useMutation({
    mutationFn: () => purchaseAPI.addToCart({ buy_count: currentQuantity, product_id: product?._id as string }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["cart", { status: purchasesStatus.inCart }] });
      toast.dismiss();
      toast.success("Thêm vào giỏ hàng thành công", {
        hideProgressBar: true,
        autoClose: 1000,
        draggable: false,
        position: "top-center",
        className: "add-to-cart-successfully-toast",
        closeOnClick: false,
      });
    },
    onError: () => {
      toast.error("Vui lòng đăng nhập!");
    },
  });
  const handleCurrentQuantity = (value: number) => {
    setCurrentQuantity(value);
  };

  const handleAddToCart = () => {
    addToCartMutation.mutate();
  };

  const handleBuyNow = async () => {
    const res = await addToCartMutation.mutateAsync();
    const purchase = res.data.data;
    navigate(path.cart, {
      state: {
        purchaseId: purchase._id,
      },
    });
  };

  const { data: wishlistData } = useQuery({
    queryKey: ["wishlist"],
    queryFn: wishlistApi.getWishlist,
    enabled: isAuthenticated,
    staleTime: 5 * 60 * 1000,
  });

  const wishlistProducts = wishlistData?.data.data || [];
  const isLiked = wishlistProducts.some((p: any) => p === product?._id || p._id === product?._id);

  const toggleWishlistMutation = useMutation({
    mutationFn: (isLikedNow: boolean) =>
      isLikedNow ? wishlistApi.removeFromWishlist(product!._id) : wishlistApi.addToWishlist(product!._id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["wishlist"] });
    },
  });

  const handleToggleWishlist = () => {
    if (!isAuthenticated) {
      toast.info("Vui lòng đăng nhập để thêm vào danh sách yêu thích");
      return;
    }
    toggleWishlistMutation.mutate(isLiked);
  };

  const handleEnterZoomMode = (e: React.MouseEvent<HTMLImageElement, MouseEvent>) => {
    setCurrentImageState(e.currentTarget);
  };

  const handleZoom = (event: React.MouseEvent<HTMLDivElement, MouseEvent>) => {
    const rect = event.currentTarget.getBoundingClientRect();
    if (currentImageState) {
      const image = currentImageState as HTMLImageElement;
      const { naturalHeight, naturalWidth } = image;
      const offsetX = event.pageX - (rect.x + window.scrollX);
      const offsetY = event.pageY - (rect.y + window.scrollY);

      const top = offsetY * (1 - naturalHeight / rect.height);
      const left = offsetX * (1 - naturalWidth / rect.width);
      image.style.width = naturalWidth + "px";
      image.style.height = naturalHeight + "px";
      image.style.maxWidth = "unset";
      image.style.top = top + "px";
      image.style.left = left + "px";
    }
  };

  const handleRemoveZoom = () => {
    const image = currentImageState as HTMLImageElement;
    setCurrentImageState(null);
    image.removeAttribute("style");
  };

  if (!product) {
    return (
      <div className="bg-gray-200 py-6">
        <div className="bg-white p-4 shadow">
          <div className="container">
            <div className="animate-pulse lg:grid lg:grid-cols-12 lg:gap-9">
              <div className="block lg:col-span-5">
                <div className="w-full rounded-sm bg-gray-200 pt-[100%]"></div>
                <div className="mt-4 flex gap-2">
                  {[1, 2, 3, 4, 5].map((i) => (
                    <div
                      key={i}
                      className="flex-1 rounded-sm bg-gray-200 pt-[20%]"
                    ></div>
                  ))}
                </div>
              </div>
              <div className="mt-5 block lg:col-span-7">
                <div className="mb-6 h-8 w-3/4 rounded bg-gray-200"></div>
                <div className="mb-6 flex gap-4">
                  <div className="h-5 w-20 rounded bg-gray-200"></div>
                  <div className="h-5 w-20 rounded bg-gray-200"></div>
                </div>
                <div className="mb-8 h-16 w-full rounded bg-gray-200"></div>
                <div className="mb-8 h-10 w-32 rounded bg-gray-200"></div>
                <div className="flex gap-4">
                  <div className="h-12 flex-1 rounded bg-gray-200"></div>
                  <div className="h-12 flex-1 rounded bg-gray-200"></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-gray-200 py-6">
      <Helmet>
        <title>{product.name}</title>
        <meta
          name="description"
          content={`${convert(product.description, {
            limits: { maxInputLength: 170 },
            preserveNewlines: false,
          })}`}
        />
      </Helmet>
      <div className="bg-white p-4 shadow">
        <div className="container">
          <div className="lg:grid lg:grid-cols-12 lg:gap-9">
            <div className="block lg:col-span-5">
              <Swiper
                thumbs={{ swiper: thumbSwiper && !thumbSwiper.destroyed ? thumbSwiper : null }}
                spaceBetween={10}
                grabCursor={true}
                preventInteractionOnTransition={true}
                modules={[Thumbs]}
                className="transition-all duration-200 hover:shadow-bottom-spread active:pointer-events-none"
              >
                {product.video && (
                  <SwiperSlide key="video">
                    <div className="relative flex w-full items-center justify-center overflow-hidden bg-black pt-[100%]">
                      <video
                        src={product.video}
                        controls
                        className="absolute top-0 left-0 h-full w-full object-contain"
                      >
                        <track
                          kind="captions"
                          srcLang="vi"
                          label="Tiếng Việt"
                        />
                      </video>
                    </div>
                  </SwiperSlide>
                )}
                {product.images.map((image) => {
                  return (
                    <SwiperSlide key={image}>
                      <div
                        className="relative w-full overflow-hidden pt-[100%]"
                        onMouseMove={handleZoom}
                        onMouseLeave={handleRemoveZoom}
                      >
                        <img
                          src={image}
                          alt={product.name}
                          onMouseEnter={handleEnterZoomMode}
                          aria-hidden={true}
                          className="absolute top-0 left-0 h-full w-full cursor-zoom-in bg-white object-cover"
                          loading="lazy"
                        />
                      </div>
                    </SwiperSlide>
                  );
                })}
              </Swiper>
              <Swiper
                onSwiper={setThumbSwiper}
                className="mt-4"
                grabCursor={true}
                breakpoints={{
                  320: {
                    slidesPerView: 3,
                    spaceBetween: 10,
                    freeMode: true,
                  },
                  1024: {
                    slidesPerView: 5,
                    spaceBetween: 10,
                  },
                }}
                navigation={true}
                modules={[Navigation, Thumbs, FreeMode]}
              >
                {product.video && (
                  <SwiperSlide key="video-thumb">
                    <div className="relative flex w-full cursor-pointer items-center justify-center bg-black pt-[100%]">
                      <svg
                        viewBox="0 0 24 24"
                        fill="white"
                        className="absolute z-10 h-8 w-8 opacity-80"
                        xmlns="http://www.w3.org/2000/svg"
                      >
                        <path d="M8 5v14l11-7z" />
                      </svg>
                      <video
                        src={product.video}
                        className="absolute top-0 left-0 h-full w-full object-cover opacity-60"
                      >
                        <track
                          kind="captions"
                          srcLang="vi"
                          label="Tiếng Việt"
                        />
                      </video>
                    </div>
                  </SwiperSlide>
                )}
                {product.images.map((image) => {
                  return (
                    <SwiperSlide key={image}>
                      <div className="relative w-full pt-[100%]">
                        <img
                          src={image}
                          alt={product.name}
                          className="absolute top-0 left-0 h-full w-full cursor-pointer bg-white object-cover"
                          loading="lazy"
                        />
                      </div>
                    </SwiperSlide>
                  );
                })}
              </Swiper>
            </div>
            <div className="mt-5 block lg:col-span-7">
              <h1 className="text-xl font-medium uppercase">{product.name}</h1>
              <div className="mt-8 flex items-center">
                <div className="flex items-center">
                  <span className="mr-1 border-b border-b-primary text-primary">{product.rating}</span>
                  <ProductRating
                    rating={product.rating}
                    activeClassName="fill-primary text-primary h-4 w-4"
                    nonActiveClassName="fill-gray-300 text-gray-300 h-4 w-4"
                  />
                </div>
                <div className="mx-4 h-4 w-[1px] bg-gray-300"></div>
                <div>
                  <span>{formatNumberToSocialStyle(product.sold)}</span>
                  <span className="ml-1 text-gray-500">Đã bán</span>
                </div>
              </div>
              <div className="mt-8 flex items-center gap-x-4 bg-gray-50 px-5 py-4">
                <div className="text-gray-500 line-through">₫{formatCurrency(product.price_before_discount)}</div>
                <div className="text-2xl font-medium text-primary sm:text-3xl">₫{formatCurrency(product.price)}</div>
                <div className="rounded-sm bg-primary px-1 py-[2px] text-xs font-semibold uppercase text-white">
                  {calculateSalePercent(product.price_before_discount, product.price)} giảm
                </div>
              </div>
              <div className="mt-8 flex items-center">
                <div className="capitalize text-gray-500">Số lượng</div>
                <QuantityController
                  type="text"
                  onDecrease={handleCurrentQuantity}
                  onIncrease={handleCurrentQuantity}
                  onType={handleCurrentQuantity}
                  value={currentQuantity}
                  max={product.quantity}
                  containerClassName="ml-10"
                ></QuantityController>
                <div className="ml-6 text-sm text-gray-500">{product.quantity} sản phẩm có sẵn</div>
              </div>
              <div className="mt-8 sm:flex sm:items-center sm:gap-x-4">
                <button
                  onClick={handleAddToCart}
                  className="flex h-12 w-full items-center justify-center rounded-sm border border-primary bg-primary/10 px-5 capitalize text-primary shadow-sm hover:bg-primary/5 sm:w-auto"
                >
                  <svg
                    enableBackground="new 0 0 15 15"
                    viewBox="0 0 15 15"
                    x={0}
                    y={0}
                    className="mr-[10px] h-5 w-5 fill-current stroke-primary text-primary"
                  >
                    <g>
                      <g>
                        <polyline
                          fill="none"
                          points=".5 .5 2.7 .5 5.2 11 12.4 11 14.5 3.5 3.7 3.5"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeMiterlimit={10}
                        />
                        <circle
                          cx={6}
                          cy="13.5"
                          r={1}
                          stroke="none"
                        />
                        <circle
                          cx="11.5"
                          cy="13.5"
                          r={1}
                          stroke="none"
                        />
                      </g>
                      <line
                        fill="none"
                        strokeLinecap="round"
                        strokeMiterlimit={10}
                        x1="7.5"
                        x2="10.5"
                        y1={7}
                        y2={7}
                      />
                      <line
                        fill="none"
                        strokeLinecap="round"
                        strokeMiterlimit={10}
                        x1={9}
                        x2={9}
                        y1="8.5"
                        y2="5.5"
                      />
                    </g>
                  </svg>
                  Thêm vào giỏ hàng
                </button>
                <button
                  onClick={handleBuyNow}
                  className="mt-5 flex h-12 w-full min-w-[5rem] items-center justify-center rounded-sm bg-primary px-5 capitalize text-white shadow-sm outline-none hover:bg-primary/90 sm:mt-0 sm:w-auto"
                >
                  Mua ngay
                </button>
                <button
                  onClick={handleToggleWishlist}
                  className="mt-5 flex h-12 w-full min-w-[5rem] items-center justify-center gap-2 rounded-sm border border-gray-300 px-5 capitalize text-gray-600 shadow-sm outline-none hover:bg-gray-50 sm:mt-0 sm:w-auto"
                >
                  <svg
                    viewBox="0 0 24 24"
                    className={`h-5 w-5 ${isLiked ? "fill-primary" : "fill-none stroke-gray-500 stroke-2"}`}
                  >
                    <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z" />
                  </svg>
                  Yêu thích
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
      <div className="mt-8 bg-white p-4 shadow">
        <div className="container">
          <div className="rounded bg-gray-50 p-4 text-lg capitalize text-slate-700">Mô tả sản phẩm</div>
          <div className="mx-4 mt-12 mb-4 text-sm leading-loose">
            <div
              dangerouslySetInnerHTML={{
                __html: DOMPurify.sanitize(product.description),
              }}
            />
