        </div>
      </div>
      <ProductReviews
        productId={product._id}
        productRating={product.rating}
      />
      <div className="container mt-8">
        <Recommendations categoryId={product.category._id} />
      </div>
      <div className="container">
        <h2 className="mt-5 uppercase">Các sản phẩm liên quan khác</h2>
        <div className="mt-6 grid grid-cols-2 gap-3 md:grid-cols-4 lg:grid-cols-6">
          {relevantProductListData &&
            relevantProductListData.data.data.products.map((product) => (
              <div
                className="col-span-1"
                key={product._id}
              >
                <Product product={product}></Product>
              </div>
            ))}
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useState } from "react";
import { toast } from "react-toastify";
import reviewApi from "src/apis/review.api";
import Button from "src/components/Button";
import ProductRating from "src/components/ProductRating";
import getAvatarUrl from "src/utils/getAvatarUrl";

type ProductReviewsProps = {
  productId: string;
  productRating: number;
};

export default function ProductReviews({ productId, productRating }: ProductReviewsProps) {
  const [ratingFilter, setRatingFilter] = useState<number>(0);
  const [page, setPage] = useState<number>(1);
  const [showReviewForm, setShowReviewForm] = useState(false);
  const [newRating, setNewRating] = useState<number>(5);
  const [newComment, setNewComment] = useState("");

  const queryClient = useQueryClient();

  const { data: reviewsData } = useQuery({
    queryKey: ["reviews", productId, { rating: ratingFilter, page }],
    queryFn: () => reviewApi.getReviews(productId, { rating: ratingFilter, page, limit: 5 }),
    keepPreviousData: true,
  });

  const reviewsInfo = reviewsData?.data.data;
  const reviews = reviewsInfo?.reviews || [];
  const ratingDistribution = reviewsInfo?.ratingDistribution;

  const createReviewMutation = useMutation({
    mutationFn: (body: { rating: number; comment: string }) => reviewApi.createReview(productId, body),
    onSuccess: () => {
      toast.success("Đánh giá sản phẩm thành công");
      setShowReviewForm(false);
      setNewComment("");
      setNewRating(5);
      queryClient.invalidateQueries({ queryKey: ["reviews", productId] });
      queryClient.invalidateQueries({ queryKey: ["product", productId] });
    },
    onError: (error: any) => {
      if (error.response?.status === 403) {
        toast.error("Bạn chưa mua sản phẩm này nên không thể đánh giá");
      } else {
        toast.error("Có lỗi xảy ra khi gửi đánh giá");
      }
    },
  });

  const handlePostReview = () => {
    if (!newComment.trim()) {
      toast.error("Vui lòng nhập nội dung đánh giá");
      return;
    }
    createReviewMutation.mutate({ rating: newRating, comment: newComment });
  };

  return (
    <div className="mt-8 bg-white p-4 shadow">
      <div className="container">
        <div className="rounded bg-gray-50 p-4 text-lg capitalize text-slate-700">Đánh giá sản phẩm</div>

        <div className="mt-4 flex flex-col gap-8 rounded-sm border border-primary/20 bg-primary/5 p-6 md:flex-row">
          <div className="flex min-w-[150px] flex-col items-center justify-center">
            <div className="text-4xl font-bold text-primary">
              <span className="text-5xl">{productRating}</span>
              <span className="text-2xl"> trên 5</span>
            </div>
            <div className="mt-2">
              <ProductRating
                rating={productRating}
                activeClassName="fill-primary text-primary h-6 w-6"
                nonActiveClassName="fill-gray-300 text-gray-300 h-6 w-6"
              />
            </div>
          </div>

          <div className="flex flex-wrap items-start gap-2">
            <button
              onClick={() => {
                setRatingFilter(0);
                setPage(1);
              }}
              className={`rounded-sm border px-5 py-2 ${
                ratingFilter === 0 ? "border-primary bg-white text-primary" : "border-gray-200 bg-white"
              }`}
            >
              Tất cả ({reviewsInfo?.totalReviews || 0})
            </button>
            {[5, 4, 3, 2, 1].map((star) => (
              <button
                key={star}
                onClick={() => {
                  setRatingFilter(star);
                  setPage(1);
                }}
                className={`rounded-sm border px-5 py-2 ${
                  ratingFilter === star ? "border-primary bg-white text-primary" : "border-gray-200 bg-white"
                }`}
              >
                {star} Sao ({ratingDistribution?.[star as unknown as keyof typeof ratingDistribution] || 0})
              </button>
            ))}
          </div>

          <div className="ml-auto flex items-center">
            <Button
              className="rounded-sm bg-primary px-6 py-2 text-white hover:bg-primary/90"
              onClick={() => setShowReviewForm(!showReviewForm)}
            >
              Viết đánh giá
            </Button>
          </div>
        </div>

        {showReviewForm && (
          <div className="mt-4 rounded-sm border border-gray-200 p-4">
            <h3 className="mb-3 font-medium">Gửi đánh giá của bạn</h3>
            <div className="mb-4 flex items-center gap-2">
              <span>Chất lượng sản phẩm:</span>
              <div className="flex">
                {[1, 2, 3, 4, 5].map((star) => (
                  <svg
                    key={star}
                    onClick={() => setNewRating(star)}
                    className={`h-8 w-8 cursor-pointer ${
                      star <= newRating ? "fill-primary text-primary" : "fill-gray-300 text-gray-300"
                    }`}
                    viewBox="0 0 15 15"
                  >
                    <polygon
                      points="7.5 .8 9.7 5.4 14.5 5.9 10.7 9.1 11.8 14.2 7.5 11.6 3.2 14.2 4.3 9.1 .5 5.9 5.3 5.4"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeMiterlimit="10"
                    />
                  </svg>
                ))}
              </div>
            </div>
            <textarea
              className="w-full rounded-sm border border-gray-300 p-3 outline-none focus:border-primary"
              rows={4}
              placeholder="Chia sẻ nhận xét của bạn về sản phẩm này..."
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
            />
            <div className="mt-3 flex justify-end">
              <Button
                className="rounded-sm bg-primary px-6 py-2 text-white"
                onClick={handlePostReview}
                isLoading={createReviewMutation.isLoading}
                disabled={createReviewMutation.isLoading}
              >
                Gửi
              </Button>
            </div>
          </div>
        )}

        <div className="mt-6">
          {reviews.length === 0 ? (
            <div className="py-10 text-center text-gray-500">Chưa có đánh giá nào</div>
          ) : (
            <div className="flex flex-col gap-6">
              {reviews.map((review) => (
                <div
                  key={review._id}
                  className="flex gap-4 border-b border-gray-100 pb-6"
                >
                  <img
                    src={getAvatarUrl(review.user.avatar, review.user.email)}
                    alt={review.user.name || "avatar"}
                    className="h-10 w-10 rounded-full object-cover"
                  />
                  <div className="flex-1">
                    <div className="text-sm font-medium">{review.user.name || review.user.email}</div>
                    <div className="mt-1">
                      <ProductRating
                        rating={review.rating}
                        activeClassName="fill-primary text-primary h-3 w-3"
                        nonActiveClassName="fill-gray-300 text-gray-300 h-3 w-3"
                      />
                    </div>
                    <div className="mt-1 text-xs text-gray-400">
                      {new Date(review.createdAt).toLocaleString("vi-VN")}
                    </div>
                    <div className="mt-3 whitespace-pre-wrap text-sm leading-6">{review.comment}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {reviewsInfo && reviewsInfo.pagination.page_size > 1 && (
          <div className="mt-6 flex justify-center gap-2">
            {Array.from({ length: reviewsInfo.pagination.page_size }).map((_, i) => {
              const pageNumber = i + 1;
              return (
                <button
                  key={pageNumber}
                  onClick={() => setPage(pageNumber)}
                  className={`rounded-sm border px-3 py-1 ${
                    page === pageNumber
                      ? "border-primary bg-primary text-white"
                      : "border-gray-300 bg-white text-gray-500 hover:bg-gray-50"
                  }`}
                >
                  {pageNumber}
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import { useQuery } from "@tanstack/react-query";
import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import promotionApi from "src/apis/promotion.api";
import { path } from "src/constants/path.enum";
import { formatCurrency } from "src/utils/formatNumber";
import { generateSlug } from "src/utils/slugify";

const FlashSale = () => {
  const { data: promotionsData } = useQuery({
    queryKey: ["activePromotions"],
    queryFn: () => promotionApi.getActivePromotions(),
    staleTime: 3 * 60 * 1000,
  });

  const promotions = promotionsData?.data.data || [];
  const [timeLeft, setTimeLeft] = useState<{ hours: string; minutes: string; seconds: string } | null>(null);

  useEffect(() => {
    if (promotions.length === 0) return;

    // Using the end_time of the first promotion as the target
    const targetDate = new Date(promotions[0].end_time).getTime();

    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = targetDate - now;

      if (distance < 0) {
        clearInterval(interval);
        setTimeLeft(null);
      } else {
        const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((distance % (1000 * 60)) / 1000);

        setTimeLeft({
          hours: String(hours).padStart(2, "0"),
          minutes: String(minutes).padStart(2, "0"),
          seconds: String(seconds).padStart(2, "0"),
        });
      }
    }, 1000);

    return () => clearInterval(interval);
  }, [promotions]);

  if (!promotions || promotions.length === 0) return null;

  return (
    <div className="mb-6 rounded bg-white shadow">
      <div className="flex items-center justify-between border-b border-gray-200 p-4">
        <div className="flex items-center gap-4">
          <div className="text-2xl font-bold uppercase italic text-primary">Flash Sale</div>
          {timeLeft && (
            <div className="flex items-center gap-1">
              <span className="flex h-7 w-7 items-center justify-center rounded bg-black text-sm font-bold text-white">
                {timeLeft.hours}
              </span>
              <span className="font-bold text-black">:</span>
              <span className="flex h-7 w-7 items-center justify-center rounded bg-black text-sm font-bold text-white">
                {timeLeft.minutes}
              </span>
              <span className="font-bold text-black">:</span>
              <span className="flex h-7 w-7 items-center justify-center rounded bg-black text-sm font-bold text-white">
                {timeLeft.seconds}
              </span>
            </div>
          )}
        </div>
        <div className="cursor-pointer text-sm text-primary hover:opacity-80">Xem tất cả {`>`}</div>
      </div>
      <div className="grid grid-cols-2 gap-3 p-4 md:grid-cols-4 lg:grid-cols-5">
        {promotions.slice(0, 5).map((promo) => {
          const product = promo.product;
          const soldPercentage = Math.min(100, (product.sold / (product.quantity + product.sold)) * 100);

          return (
            <Link
              to={`${path.home}${generateSlug({ name: product.name, id: product._id })}`}
              className="col-span-1"
              key={promo._id}
            >
              <div className="relative rounded-sm border border-transparent bg-white shadow transition-transform duration-100 hover:-translate-y-[1px] hover:border-primary hover:shadow-md">
                <div className="relative w-full pt-[100%]">
                  <img
                    src={product.image}
                    alt={product.name}
                    className="absolute top-0 left-0 h-full w-full bg-white object-cover"
                  />
                  <div className="absolute top-0 right-0 rounded-bl-sm rounded-tr-sm bg-[#ffd839] px-1 py-[2px]">
                    <div className="text-center text-xs font-semibold uppercase text-[#ee4d2d]">
                      {promo.discount_percent}% giảm
                    </div>
                  </div>
                </div>
                <div className="p-3">
                  <div className="text-center text-lg font-medium text-primary">
                    ₫{formatCurrency(product.price * (1 - promo.discount_percent / 100))}
                  </div>
                  <div className="relative mt-3 h-4 w-full overflow-hidden rounded-full bg-[#ffbda6]">
                    <div
